import React from 'react'
import Room from './Room';
import { Link } from 'react-router-dom';

export default function MyRooms(props) {
    let showRooms=()=>{
        if(props.rooms!=[])
        props.rooms.map((i) => { return <Room room={i} /> })}
  return (
    <div>
    {showRooms()}
    <Link to={"/"}><button>Back</button> </Link>
    </div>
  )
}
